                continue
            }
            if (attrUri.scheme != null) continue

            val path = Paths.get(mediaDir, attrUri.path).toString()
            val newUri = getFileUri(path)

            elem.attr(attr, newUri.toString())
            madeChanges = true
        }
        return madeChanges
    }","new_string":"    fun replaceWithFileScheme(tag: String, attr: String): Boolean {
        fun fragmentLooksLikeFilenameContinuation(path: String, fragment: String): Boolean {
            // When a filename contains an unescaped '#', java.net.URI treats everything after the '#'
            // as a fragment, and it gets dropped from `path`.
            // Eg: "foo#bar.jpg" -> path="foo", fragment="bar.jpg".
            //
            // We only treat the fragment as a filename continuation when the path has no extension,
            // and the fragment does.
            val pathLeaf = path.substringAfterLast('/')
            val pathHasExtension = '.' in pathLeaf
            val fragmentHasExtension = '.' in fragment
            return !pathHasExtension && fragmentHasExtension
        }

        var madeChanges = false
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue

            val attrUri = try {
                URI(attrValue)
            } catch (_: URISyntaxException) {
                continue
            }
            if (attrUri.scheme != null) continue

            val relativePath = if (attrUri.fragment != null && fragmentLooksLikeFilenameContinuation(attrUri.path, attrUri.fragment)) {
                "${attrUri.path}#${attrUri.fragment}"
            } else {
                attrUri.path
            }

            val path = Paths.get(mediaDir, relativePath).toString()
            val newUri = getFileUri(path)

            elem.attr(attr, newUri.toString())
            madeChanges = true
        }
        return madeChanges
    }"}

